# .github/branch-protection.yml  (managed via Terraform or gh CLI)
# Applying via gh CLI:
# gh api repos/{owner}/{repo}/branches/main/protection --method PUT --input protection.json

{
  "required_status_checks": {
    "strict": true,
    "contexts": ["lint", "test", "eval-suite", "secret-scan"]
  },
  "enforce_admins": true,
  "required_pull_request_reviews": {
    "required_approving_review_count": 1,
    "dismiss_stale_reviews": true,
    "require_code_owner_reviews": true
  },
  "restrictions": null
}

# Wrong: swallows errors silently — agent appears to succeed when tool fails
def call_external_api(payload: dict) -> dict:
    try:
        response = requests.post(API_URL, json=payload, timeout=10)
        return response.json()
    except Exception:
        pass  # reviewer should block this

# Right: surface errors explicitly so the orchestrator can handle them
def call_external_api(payload: dict) -> dict:
    try:
        response = requests.post(API_URL, json=payload, timeout=10)
        response.raise_for_status()
        return response.json()
    except requests.exceptions.Timeout:
        raise ToolError("External API timed out after 10 seconds")
    except requests.exceptions.HTTPError as exc:
        raise ToolError(f"External API returned {exc.response.status_code}")
